 1	import * as React from 'react';
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  HelperText,
 6	  HelperTextItem,
 7	} from '@patternfly/react-core';
 8	import cx from 'classnames';
 9	import { useField, useFormikContext, FormikValues } from 'formik';
10	import { FieldProps } from '../pipelines-details/multi-column-field/types';
11	import { getFieldId } from '../pipelines-details/multi-column-field/utils';
12	import { useFormikValidationFix } from '../pipelines-details/multi-column-field/formik-validation-fix';
13	import { Dropdown } from './dropdown';
14	import { RedExclamationCircleIcon } from '@openshift-console/dynamic-plugin-sdk';
15	
16	export interface DropdownFieldProps extends FieldProps {
17	  items?: object;
18	  selectedKey?: string;
19	  title?: React.ReactNode;
20	  fullWidth?: boolean;
21	  disabled?: boolean;
22	  autocompleteFilter?: (text: string, item: object, key?: string) => boolean;
23	  onChange?: (value: string) => void;
24	  placeholder?: string;
25	}
26	
27	const DropdownField: React.FC<DropdownFieldProps> = ({
28	  label,
29	  helpText,
30	  required,
31	  ...props
32	}) => {
33	  const [field, { touched, error }] = useField(props.name);
34	  const { setFieldValue, setFieldTouched } = useFormikContext<FormikValues>();
35	  const fieldId = getFieldId(props.name, 'dropdown');
36	  const isValid = !(touched && error);
37	  const errorMessage = !isValid ? error : '';
38	
39	  useFormikValidationFix(field.value);
40	
41	  return (
42	    <FormGroup fieldId={fieldId} label={label} isRequired={required}>
43	      <Dropdown
44	        {...props}
45	        id={fieldId}
46	        selectedKey={field.value}
47	        dropDownClassName={cx({ 'dropdown--full-width': props.fullWidth })}
48	        aria-describedby={helpText ? `${fieldId}-helper` : undefined}
49	        onChange={(value: string) => {
50	          props.onChange && props.onChange(value);
51	          // Validation is automatically done by the useFormikValidationFix above
52	          setFieldValue(props.name, value, false);
53	          setFieldTouched(props.name, true, false);
54	        }}
55	      />
56	
57	      <FormHelperText>
58	        <HelperText>
59	          {!isValid ? (
60	            <HelperTextItem variant="error" icon={<RedExclamationCircleIcon />}>
61	              {errorMessage}
62	            </HelperTextItem>
63	          ) : (
64	            <HelperTextItem>{helpText}</HelperTextItem>
65	          )}
66	        </HelperText>
67	      </FormHelperText>
68	    </FormGroup>
69	  );
70	};
71	
72	export default DropdownField;

